external_knowledge:
- 'well-known guest' refers to 'John Doe';
- 'typical score' refers to the average rating;
- 'works featuring' indicates the media content related to the guest;
- 'published pieces' means the content has a published status of 1.

sql:
SELECT SUM(views) AS total_views
FROM media_content
WHERE guest_subject = 'Manchester Arena incident';

SELECT content_id, SUM(views) AS total_views
FROM media_content
GROUP BY content_id;

SELECT COUNT(*) AS total_views
FROM user_activity
WHERE activity_type = 'view';

SELECT title
FROM media_content
WHERE content_id = 1;

SELECT views AS total_views
FROM media_content
WHERE content_id = 1;

SELECT content_id, views
FROM media_content
ORDER BY views DESC;

SELECT COUNT(*) AS total_high_ratings
FROM content_ratings
WHERE rating > 4;
